private double Solve( final univariate real function f, final double min, final double minvalue, final double max, final double maxvalue, final double initial, final double initialvalue)
    throw max iterationsexceeded exception,functionevaluation exception{

    double midpoint = (min + max / 2);
    double midvalue = f.value(midpoint);

    if (abs(midvalue) < abs( initialvalue)) {
        setresult( midpoint, midvalue);
        return result;
    }

    if (minvalue * midvalue <0){
        return Solve(f, min, minvalue, midpoint, midvalue, initial, initialvalue);
    } else {
        return Solve(f, midpoint, midvalue, max, maxvalue, initial, initialvalue);
    }
}

